import boto3
from selenium import webdriver
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC

s3 = boto3.client('s3')
chrome_options = webdriver.ChromeOptions()
chrome_options.add_argument("--headless")
chrome_options.add_argument("--no-sandbox")
chrome_options.add_argument("--disable-gpu")
chrome_options.add_argument("--window-size=1280x1696")
driver = webdriver.Chrome(executable_path='/path/to/chromedriver', options=chrome_options)

def screenshot(url):
    driver.get(url)
    WebDriverWait(driver, 10).until(EC.element_to_be_clickable((By.CSS_SELECTOR, 'body')))
    # Get the HTML content of the page
    html = driver.page_source
    # Use BeautifulSoup to parse the HTML and get the <meta> tag for the thumbnail preview
    soup = BeautifulSoup(html, 'lxml')
    meta = soup.find('meta', attrs={'property': 'og:image'})
    if meta:
        image_url = meta['content']
        # Download the image from the URL and save it to S3
        s3.put_object(Body=image_url, Bucket='your-bucket-name', Key='your-key-prefix/image.jpg')
    else:
        print('No thumbnail preview found')
    driver.quit()